import { Component, Prop, h, Element, Event, EventEmitter, State, Method, Watch, Host, AttachInternals } from '@stencil/core';
import { createEvent, generateRandId } from '../../utils/utils';
import { TextFieldRequirementIndicator, TextFieldType } from './wdpr-text-field.model';

@Component({
  tag: 'wdpr-text-field',
  styleUrl: 'wdpr-text-field.css',
  scoped: true,
  formAssociated: true,
})
export class WdprTextField {
  /**
   * Reference to the native `<input>` element.
   */
  private _nativeInput?: HTMLInputElement;
  private _internals: ElementInternals;
  private _defaultValue = '';

  /**
   * Reference to host element
   * @type {HTMLWdprButtonElement}
   */
  @Element() el: HTMLElement;

  @AttachInternals() internals: ElementInternals;

  /**
   * The internal ID for the component. It is used internally and is not exposed.
   */
  @State() _internalId: string;
  @State() _leadingIcon?: HTMLSlotElement | null;
  @State() _trailingIcon?: HTMLSlotElement | null;

  /**
   * (Optional) A unique ID for the component. It is essential for accessibility,
   * as it connects the `<label>` to the `<input>` control.
   * If not provided, a random ID will be generated.
   */
  @Prop() inputId: string;
  @Prop() autocomplete: string;
  @Prop() name: string;
  @Prop() maxLength?: number;
  @Prop() type: TextFieldType = 'text';

  @Prop({ mutable: true }) value: string = '';
  @Prop() helperText: string = '';
  @Prop() disabled = false;
  @Prop() error = false;
  @Prop() readonly = false;
  @Prop() customTabindex = 0;
  @Prop() label: string = 'Label';
  @Prop() requirementIndicator: TextFieldRequirementIndicator = 'none';

  @Prop({ attribute: 'a11y-role' })
  a11yRole?: 'button' | 'checkbox' | 'combobox' | 'listbox' | 'menu' | 'menubar' | 'option' | 'radio' | 'searchbox' | 'textbox' | string;
  @Prop({ attribute: 'a11y-has-popup' }) a11yHasPopup?: 'false' | 'true' | 'menu' | 'listbox' | 'tree' | 'grid' | 'dialog';
  @Prop({ attribute: 'a11y-controls' }) a11yControls?: string;
  @Prop({ attribute: 'a11y-expanded' }) a11yExpanded?: 'true' | 'false';
  @Prop({ attribute: 'a11y-auto-complete' }) a11yAutoComplete?: 'none' | 'inline' | 'list' | 'both';
  @Prop({ attribute: 'a11y-active-descendant' }) a11yActiveDescendant?: string;
  @Prop({ attribute: 'a11y-disabled' }) a11yDisabled?: 'true' | 'false';
  @Prop({ attribute: 'a11y-required' }) a11yRequired?: 'true' | 'false';
  @Prop({ attribute: 'a11y-described-by' }) a11yDescribedBy?: string;

  @Event() wdprValueChanged: EventEmitter<string>;
  @Event() wdprInputFocus: EventEmitter<void>;
  @Event() wdprInputBlur: EventEmitter<void>;
  @Event() wdprInputClick: EventEmitter<void>;
  @Event() wdprLeadingIconClick: EventEmitter<boolean>;
  @Event() wdprTrailingIconClick: EventEmitter<{ value: string }>;

  @Watch('disabled')
  updateDisabledState() {
    this._updateButtonsDisabledState();
  }

  @Watch('value')
  _handleValueChange(nextValue: string): void {
    const displayValue = this._getDisplayValue(nextValue);

    if (displayValue !== (nextValue ?? '')) {
      this.value = displayValue;

      return;
    }

    this._syncInternals(displayValue);
    this._syncNativeValue(displayValue);
  }

  /**
   * Sets focus on the native `<input>` element.
   * Usage: textField.setFocus();
   */
  @Method()
  async setFocus() {
    this._nativeInput?.focus();
  }

  connectedCallback() {
    let initialValue = '';

    if (this.readonly && !this.value) {
      initialValue = '--';
    } else if (this.value) {
      initialValue = this.value;
    }

    const displayValue = this._getDisplayValue(initialValue);

    this.value = displayValue;
    this._defaultValue = displayValue;
    this._syncInternals(displayValue);
    this.el.addEventListener('formreset', this._handleFormReset);
  }

  disconnectedCallback() {
    this.el.removeEventListener('formreset', this._handleFormReset);
  }

  componentWillLoad() {
    this._internalId = this.inputId || `wdpr-text-field-${generateRandId()}`;

    this._updateButtonsDisabledState();
  }

  componentDidLoad() {
    this._syncNativeValue(this.value);
  }

  private _updateButtonsDisabledState = () => {
    this._leadingIcon = this.el.querySelector('[slot="leading-icon-button"]');
    this._trailingIcon = this.el.querySelector('[slot="trailing-icon-button"]');

    this._leadingIcon?.setAttribute('disabled', this.disabled.toString());
    this._trailingIcon?.setAttribute('disabled', this.disabled.toString());
  };

  private _handleSlotChange = () => {
    this.updateDisabledState();
  };

  private _handleFormReset = () => {
    this.value = this._defaultValue ?? '';
  };

  private _syncInternals(value: string) {
    this._internals?.setFormValue?.(value ?? '');
  }

  private _getDisplayValue(rawValue: string): string {
    const withReadonlyPlaceholder = this.readonly && !rawValue ? '--' : rawValue ?? '';

    const max = typeof this.maxLength === 'number' && Number.isFinite(this.maxLength) ? this.maxLength : undefined;
    if (!max || max <= 0) return withReadonlyPlaceholder;

    return withReadonlyPlaceholder.length > max ? withReadonlyPlaceholder.slice(0, max) : withReadonlyPlaceholder;
  }

  private _syncNativeValue(value: string) {
    const displayValue = this._getDisplayValue(value);

    if (this._nativeInput && this._nativeInput.value !== displayValue) {
      this._nativeInput.value = displayValue ?? '';
    }
  }

  private _emitNativeEvents() {
    const inputEvent = createEvent('input', { bubbles: true, composed: true, cancelable: true, detail: this.value });
    this.el.dispatchEvent(inputEvent);
    const changeEvent = createEvent('change', { bubbles: true, composed: true, cancelable: true });
    this.el.dispatchEvent(changeEvent);
  }

  private _onLeadingClick = () => {
    this.wdprLeadingIconClick.emit(true);
    this._leadingIcon?.blur();
  };

  private _onTrailingClick = () => {
    const oldValue = this.value;
    this.wdprTrailingIconClick.emit({ value: oldValue });
    this._trailingIcon?.blur();
  };

  private _handleInput = (event: Event) => {
    const input = event.target as HTMLInputElement;
    const nextValue = this._getDisplayValue(input.value);

    this.value = nextValue;

    if (input.value !== nextValue) {
      input.value = nextValue;
    }

    this.wdprValueChanged.emit(this.value);
    this._emitNativeEvents();
  };

  private _handleFocus = () => {
    this.wdprInputFocus.emit();
  };

  private _handleBlur = () => {
    this.wdprInputBlur.emit();
  };

  private _handleClick = () => {
    this.wdprInputClick.emit();
  };

  private get _requirementLabel(): HTMLElement | null {
    if (this.requirementIndicator === 'required') return <span aria-hidden="true"> *</span>;

    if (this.requirementIndicator === 'optional') return <span> (Optional)</span>;

    return null;
  }

  render() {
    return (
      <Host>
        <div class="text-field-wrapper">
          {this._leadingIcon && (
            <span onClick={this._onLeadingClick} part="leading-icon-button-wrapper" class="icon-wrapper">
              {/* Although this is an open slot, the expected usage is to place an wdpr-icon-button here. */}
              <slot onSlotchange={this._handleSlotChange} name="leading-icon-button" />
            </span>
          )}

          <div class="input-wrapper" part="input-wrapper">
            <input
              ref={el => (this._nativeInput = el as HTMLInputElement)}
              type={this.type}
              placeholder=" "
              id={this._internalId}
              class="input"
              disabled={this.disabled}
              name={this.name}
              maxlength={this.maxLength}
              value={this._getDisplayValue(this.value)}
              tabindex={this.disabled ? -1 : this.customTabindex}
              autocomplete={this.autocomplete ? this.autocomplete : undefined}
              readonly={this.readonly}
              role={this.a11yRole}
              aria-disabled={this.a11yDisabled ?? this.disabled.toString()}
              aria-invalid={this.error.toString()}
              aria-describedby={this.a11yDescribedBy || (this.helperText ? `${this._internalId}-helper-text` : undefined)}
              aria-haspopup={this.a11yHasPopup}
              aria-controls={this.a11yControls}
              aria-expanded={this.a11yExpanded}
              aria-autocomplete={this.a11yAutoComplete}
              aria-activedescendant={this.a11yActiveDescendant}
              aria-required={this.a11yRequired}
              onInput={this._handleInput}
              onFocus={this._handleFocus}
              onBlur={this._handleBlur}
              onClick={this._handleClick}
            />

            <label htmlFor={this._internalId} class="input-label">
              {this.label} {this._requirementLabel}
            </label>
          </div>

          {this._trailingIcon && (
            <span onClick={this._onTrailingClick} part="trailing-icon-button-wrapper" class="icon-wrapper">
              {/* Although this is an open slot, the expected usage is to place an wdpr-icon-button here. */}
              <slot onSlotchange={this._handleSlotChange} name="trailing-icon-button" />
            </span>
          )}
        </div>

        {this.helperText && (
          <div class="inline-message-wrapper" part="helper-text-wrapper">
            <wdpr-inline-message id={`${this._internalId}-helper-text`} variant={this.error ? 'error' : 'informational'} size="small" role="status">{this.helperText}</wdpr-inline-message>
          </div>
        )}
      </Host>
    );
  }
}
